     8→// ---------------------------------------------------------------------------
     9→// GPU structs – must match raytracer.metal exactly
    10→// ---------------------------------------------------------------------------
    11→struct GPUTriangle {
    12→    simd_float4 v0, v1, v2, normal, color;
    13→};
    14→
    15→struct RenderUniforms {
    16→    simd_float4 camera_pos;
    17→    simd_float4 light_pos;
    18→    simd_float4 light_colour;
    19→    simd_float4 indirect_light;
    20→    simd_float4 front_v0;
    21→    simd_float4 front_v1;
    22→    simd_float4 front_v2;
    23→    float focal;
    24→    float f;
    25→    float yaw;
    26→    int triangle_count;
    27→    int screen_width;
    28→    int screen_height;
    29→    float _pad[2];
    30→};
    31→
    32→// ---------------------------------------------------------------------------
    33→// Helper: convert glm::vec3 → simd_float4 (w = 0)
    34→// ---------------------------------------------------------------------------
    35→static inline simd_float4 toFloat4(const glm::vec3& v) {
    36→    return simd_make_float4(v.x, v.y, v.z, 0.0f);
    37→}
    38→
    39→// ---------------------------------------------------------------------------
    40→// Constructor
    41→// ---------------------------------------------------------------------------
    42→MetalRenderer::MetalRenderer(int width, int height)
    43→    : _device(nullptr), _commandQueue(nullptr), _pipelineState(nullptr),
    44→      _triangleBuffer(nullptr), _uniformsBuffer(nullptr), _outputBuffer(nullptr),
    45→      _width(width), _height(height)
    46→{
    47→    @autoreleasepool {
    48→        // 1. Create device & command queue
    49→        id<MTLDevice> device = MTLCreateSystemDefaultDevice();
    50→        if (!device) {
    51→            fprintf(stderr, "[MetalRenderer] No Metal-capable GPU found.\n");
    52→            return;
    53→        }
    54→        id<MTLCommandQueue> queue = [device newCommandQueue];
    55→
    56→        // 2. Locate raytracer.metallib
    57→        NSString* path = [[NSBundle mainBundle] pathForResource:@"raytracer" ofType:@"metallib"];
    58→
    59→        if (!path) {
    60→            // Try current working directory (running from Build/)
    61→            NSString* cwd = [[NSFileManager defaultManager] currentDirectoryPath];
    62→            NSString* candidate = [NSString stringWithFormat:@"%@/raytracer.metallib", cwd];
    63→            if ([[NSFileManager defaultManager] fileExistsAtPath:candidate]) {
    64→                path = candidate;
    65→            }
    66→        }
    67→
    68→        if (!path) {
    69→            // Try directory containing the executable
    70→            NSString* execPath = [[NSProcessInfo processInfo] arguments][0];
    71→            NSString* execDir  = [execPath stringByDeletingLastPathComponent];
    72→            NSString* candidate = [execDir stringByAppendingPathComponent:@"raytracer.metallib"];
    73→            if ([[NSFileManager defaultManager] fileExistsAtPath:candidate]) {
    74→                path = candidate;
    75→            }
    76→        }
    77→
    78→        if (!path) {
    79→            fprintf(stderr, "[MetalRenderer] Could not find raytracer.metallib.\n");
    80→            return;
    81→        }
    82→
    83→        // 3. Load library
    84→        NSError* err = nil;
    85→        id<MTLLibrary> library = [device newLibraryWithURL:[NSURL fileURLWithPath:path]
    86→                                                     error:&err];
    87→        if (!library) {
    88→            fprintf(stderr, "[MetalRenderer] Failed to load metallib: %s\n",
    89→                    [[err localizedDescription] UTF8String]);
    90→            return;
    91→        }
    92→
    93→        // 4. Get compute kernel
    94→        id<MTLFunction> fn = [library newFunctionWithName:@"raytracer_kernel"];
    95→        if (!fn) {
    96→            fprintf(stderr, "[MetalRenderer] Function 'raytracer_kernel' not found in metallib.\n");
    97→            return;
    98→        }
    99→
   100→        // 5. Build compute pipeline
   101→        id<MTLComputePipelineState> pipeline =
   102→            [device newComputePipelineStateWithFunction:fn error:&err];
   103→        if (!pipeline) {
   104→            fprintf(stderr, "[MetalRenderer] Failed to create pipeline: %s\n",
   105→                    [[err localizedDescription] UTF8String]);
   106→            return;
   107→        }
   108→
   109→        // 6. Allocate persistent buffers
   110→        id<MTLBuffer> uniformsBuf =
   111→            [device newBufferWithLength:sizeof(RenderUniforms)
   112→                                options:MTLResourceStorageModeShared];
   113→
   114→        // 9 samples per pixel, each sample is a float4
   115→        NSUInteger outputBytes = (NSUInteger)width * height * 9 * sizeof(simd_float4);
   116→        id<MTLBuffer> outputBuf =
   117→            [device newBufferWithLength:outputBytes
   118→                                options:MTLResourceStorageModeShared];
   119→
   120→        // 7. Store as void* (ARC bridge – we own the references)
   121→        _device        = (__bridge_retained void*)device;
   122→        _commandQueue  = (__bridge_retained void*)queue;
   123→        _pipelineState = (__bridge_retained void*)pipeline;
   124→        _uniformsBuffer = (__bridge_retained void*)uniformsBuf;
   125→        _outputBuffer   = (__bridge_retained void*)outputBuf;
   126→
   127→        NSLog(@"Metal GPU renderer initialized: %@", device.name);
   128→    }
   129→}
   130→
   131→// ---------------------------------------------------------------------------
   132→// Destructor
   133→// ---------------------------------------------------------------------------
   134→MetalRenderer::~MetalRenderer()
   135→{
   136→    @autoreleasepool {
   137→        if (_outputBuffer)   { (void)(__bridge_transfer id<MTLBuffer>)_outputBuffer; }
   138→        if (_uniformsBuffer) { (void)(__bridge_transfer id<MTLBuffer>)_uniformsBuffer; }
   139→        if (_triangleBuffer) { (void)(__bridge_transfer id<MTLBuffer>)_triangleBuffer; }
   140→        if (_pipelineState)  { (void)(__bridge_transfer id<MTLComputePipelineState>)_pipelineState; }
   141→        if (_commandQueue)   { (void)(__bridge_transfer id<MTLCommandQueue>)_commandQueue; }
   142→        if (_device)         { (void)(__bridge_transfer id<MTLDevice>)_device; }
   143→    }
   144→}
   145→
   146→// ---------------------------------------------------------------------------
   147→// uploadTriangles
   148→// ---------------------------------------------------------------------------
   149→void MetalRenderer::uploadTriangles(const std::vector<Triangle>& tris)
   150→{
   151→    @autoreleasepool {
   152→        id<MTLDevice> device = (__bridge id<MTLDevice>)_device;
   153→        if (!device) return;
   154→
   155→        std::vector<GPUTriangle> gpuTris(tris.size());
   156→        for (size_t i = 0; i < tris.size(); ++i) {
   157→            gpuTris[i].v0     = toFloat4(tris[i].v0);
   158→            gpuTris[i].v1     = toFloat4(tris[i].v1);
   159→            gpuTris[i].v2     = toFloat4(tris[i].v2);
   160→            gpuTris[i].normal = toFloat4(tris[i].normal);
   161→            gpuTris[i].color  = toFloat4(tris[i].color);
   162→        }
   163→
   164→        NSUInteger bytes = gpuTris.size() * sizeof(GPUTriangle);
   165→        id<MTLBuffer> buf = [device newBufferWithBytes:gpuTris.data()
   166→                                                length:bytes
   167→                                               options:MTLResourceStorageModeShared];
   168→
   169→        // Release old buffer if present
   170→        if (_triangleBuffer) {
   171→            (void)(__bridge_transfer id<MTLBuffer>)_triangleBuffer;
   172→        }
   173→        _triangleBuffer = (__bridge_retained void*)buf;
   174→    }
   175→}
