   177→// ---------------------------------------------------------------------------
   178→// render
   179→// ---------------------------------------------------------------------------
   180→void MetalRenderer::render(const RenderParams& params, std::vector<glm::vec3>& pixels)
   181→{
   182→    @autoreleasepool {
   183→        id<MTLDevice>                  device   = (__bridge id<MTLDevice>)_device;
   184→        id<MTLCommandQueue>            queue    = (__bridge id<MTLCommandQueue>)_commandQueue;
   185→        id<MTLComputePipelineState>    pipeline = (__bridge id<MTLComputePipelineState>)_pipelineState;
   186→        id<MTLBuffer>                  triBuf   = (__bridge id<MTLBuffer>)_triangleBuffer;
   187→        id<MTLBuffer>                  uniBuf   = (__bridge id<MTLBuffer>)_uniformsBuffer;
   188→        id<MTLBuffer>                  outBuf   = (__bridge id<MTLBuffer>)_outputBuffer;
   189→
   190→        if (!device || !pipeline || !triBuf) {
   191→            fprintf(stderr, "[MetalRenderer] render() called before initialisation or uploadTriangles().\n");
   192→            return;
   193→        }
   194→
   195→        // 1. Fill uniforms
   196→        RenderUniforms uni;
   197→        uni.camera_pos    = toFloat4(params.camera_pos);
   198→        uni.light_pos     = toFloat4(params.light_pos);
   199→        uni.light_colour  = toFloat4(params.light_colour);
   200→        uni.indirect_light = toFloat4(params.indirect_light);
   201→        // Hardcoded front-plane vertices (must match shader)
   202→        uni.front_v0 = simd_make_float4(-0.76f, -0.87f, -1.0f, 0.0f);
   203→        uni.front_v1 = simd_make_float4(-0.76f,  1.0f,  -1.0f, 0.0f);
   204→        uni.front_v2 = simd_make_float4( 1.31f,  1.0f,  -1.0f, 0.0f);
   205→        uni.focal          = params.focal;
   206→        uni.f              = params.f;
   207→        uni.yaw            = params.yaw;
   208→        uni.triangle_count = (int)(triBuf.length / sizeof(GPUTriangle));
   209→        uni.screen_width   = params.screen_width;
   210→        uni.screen_height  = params.screen_height;
   211→        uni._pad[0]        = 0.0f;
   212→        uni._pad[1]        = 0.0f;
   213→
   214→        // 2. Copy uniforms into shared buffer
   215→        memcpy(uniBuf.contents, &uni, sizeof(RenderUniforms));
   216→
   217→        // 3. Encode compute pass
   218→        id<MTLCommandBuffer>         cmdBuf  = [queue commandBuffer];
   219→        id<MTLComputeCommandEncoder> encoder = [cmdBuf computeCommandEncoder];
   220→
   221→        [encoder setComputePipelineState:pipeline];
   222→        [encoder setBuffer:triBuf offset:0 atIndex:0];
   223→        [encoder setBuffer:uniBuf offset:0 atIndex:1];
   224→        [encoder setBuffer:outBuf offset:0 atIndex:2];
   225→
   226→        // 4. Dispatch – one thread per (x, y, sample)
   227→        MTLSize threadsPerGrid      = MTLSizeMake((NSUInteger)_width,
   228→                                                   (NSUInteger)_height,
   229→                                                   9);
   230→        MTLSize threadsPerThreadgroup = MTLSizeMake(8, 8, 1);
   231→        [encoder dispatchThreads:threadsPerGrid
   232→           threadsPerThreadgroup:threadsPerThreadgroup];
   233→
   234→        [encoder endEncoding];
   235→        [cmdBuf commit];
   236→        [cmdBuf waitUntilCompleted];
   237→
   238→        // 5. Read back: layout is [pixelIndex * 9 + sampleIndex] → simd_float4
   239→        const simd_float4* buf = reinterpret_cast<const simd_float4*>(outBuf.contents);
   240→
   241→        pixels.resize((size_t)_width * _height);
   242→        for (int y = 0; y < _height; ++y) {
   243→            for (int x = 0; x < _width; ++x) {
   244→                int pixelIdx = y * _width + x;
   245→                float r = 0.0f, g = 0.0f, b = 0.0f;
   246→                for (int s = 0; s < 9; ++s) {
   247→                    const simd_float4& sample = buf[pixelIdx * 9 + s];
   248→                    r += sample.x;
   249→                    g += sample.y;
   250→                    b += sample.z;
   251→                }
   252→                pixels[pixelIdx] = glm::vec3(r / 9.0f, g / 9.0f, b / 9.0f);
   253→            }
   254→        }
   255→    }
   256→}
