   132→void Update()
   133→{
   134→    // Compute frame time:
   135→    int t2 = SDL_GetTicks();
   136→    float dt = float(t2 - t);
   137→    t = t2;
   138→    cout << "Render time: " << dt << " ms." << endl;
   139→
   140→    Uint8* keystate = SDL_GetKeyState(0);
   141→    if (keystate[SDLK_UP])
   142→    {
   143→        // Move camera forward
   144→        camera_pos.z += 0.1f;
   145→    }
   146→    if (keystate[SDLK_DOWN])
   147→    {
   148→        // Move camera backward
   149→        camera_pos.z -= 0.1f;
   150→    }
   151→    if (keystate[SDLK_LEFT])
   152→    {
   153→        // Rotate the camera along the y axis
   154→        yaw += 0.1f;
   155→    }
   156→    if (keystate[SDLK_RIGHT])
   157→    {
   158→        // Rotate the camera along the y axis
   159→        yaw -= 0.1f;
   160→    }
   161→    if (keystate[SDLK_w])
   162→    {
   163→        // Move lightsource forward
   164→        light_pos.z += 0.1f;
   165→    }
   166→    if (keystate[SDLK_s])
   167→    {
   168→        // Move lightsource backward
   169→        light_pos.z -= 0.1f;
   170→    }
   171→    if (keystate[SDLK_a])
   172→    {
   173→        // Move lightsource left
   174→        light_pos.x -= 0.1f;
   175→    }
   176→    if (keystate[SDLK_d])
   177→    {
   178→        // Move lightsource right
   179→        light_pos.x += 0.1f;
   180→    }
   181→    if (keystate[SDLK_q])
   182→    {
   183→        // Move lightsource up
   184→        light_pos.y -= 0.1f;
   185→    }
   186→    if (keystate[SDLK_e])
   187→    {
   188→        // Move lightsource down
   189→        light_pos.y += 0.1f;
   190→    }
   191→}
