   193→void Draw()
   194→{
   195→    SDL_FillRect(screen, 0, 0);
   196→    if (SDL_MUSTLOCK(screen))
   197→        SDL_LockSurface(screen);
   198→
   199→#ifdef USE_METAL
   200→    RenderParams params;
   201→    params.camera_pos   = camera_pos;
   202→    params.light_pos    = light_pos;
   203→    params.light_colour = light_colour;
   204→    params.indirect_light = indirect_light;
   205→    params.focal        = focal;
   206→    params.f            = f;
   207→    params.yaw          = yaw;
   208→    params.screen_width  = SCREEN_WIDTH;
   209→    params.screen_height = SCREEN_HEIGHT;
   210→
   211→    std::vector<glm::vec3> pixels(SCREEN_WIDTH * SCREEN_HEIGHT);
   212→    g_metal_renderer->render(params, pixels);
   213→
   214→    for (int y = 0; y < SCREEN_HEIGHT; y++)
