   238→void *img_thread(void *arg)
   239→{
   240→    int area = *(int*)arg;
   241→    unsigned int seed = (unsigned int)(area + 1) * 12345;
   242→
   243→    vec3 black(0.0f, 0.0f, 0.0f);
   244→    Intersection intersection, mirror_intersec;
   245→    vec3 d, light_area, mirror_shadow, intersection_pos, sum_colour, pixel_colour, sub_pixel;
   246→    mat3 R(cos(yaw), 0, sin(yaw), 0, 1, 0, -sin(yaw), 0, cos(yaw));
   247→    float x, y, focal_x, focal_y;
