   249→    float srceen_width = SCREEN_WIDTH;
   250→    float screen_height = SCREEN_HEIGHT;
   251→    vec3 original_img[10][10];
   252→    int x_value, y_value;
   253→
   254→    switch (area)
   255→    {
   256→    case 0: x_value = 0;                y_value = 0;                break;
   257→    case 1: x_value = SCREEN_WIDTH / 3; y_value = 0;                break;
   258→    case 2: x_value = SCREEN_WIDTH / 3 * 2; y_value = 0;           break;
   259→    case 3: x_value = 0;                y_value = SCREEN_HEIGHT / 3; break;
   260→    case 4: x_value = SCREEN_WIDTH / 3; y_value = SCREEN_HEIGHT / 3; break;
   261→    case 5: x_value = SCREEN_WIDTH / 3 * 2; y_value = SCREEN_HEIGHT / 3; break;
   262→    case 6: x_value = 0;                y_value = SCREEN_HEIGHT / 3 * 2; break;
   263→    case 7: x_value = SCREEN_WIDTH / 3; y_value = SCREEN_HEIGHT / 3 * 2; break;
   264→    case 8: x_value = SCREEN_WIDTH / 3 * 2; y_value = SCREEN_HEIGHT / 3 * 2; break;
   265→    default:
   266→        printf("ERROR!\n");
   267→        break;
   268→    }
   269→
   270→    for (int i = 0; i < SCREEN_HEIGHT / 3; i++)
   271→    {
   272→        for (int j = 0; j < SCREEN_WIDTH / 3; j++)
   273→        {
   274→            x = j + x_value;
   275→            y = i + y_value;
   276→
   277→            focal_x = (-0.5 + 0.5 / srceen_width + x * 1.0 / srceen_width) * (focal - camera_pos[2]) / f;
   278→            focal_y = (-0.5 + 0.5 / screen_height + y * 1.0 / screen_height) * (focal - camera_pos[2]) / f;
   279→            height = 0;
   280→
   281→            for (int a = -8; a < 9; a = a + 8)
   282→            {
   283→                int width = 0;
   284→                for (int b = -8; b < 9; b = b + 8)
   285→                {
   286→                    float x_ = b - b / 2 + b / 2 * (rand_r(&seed) / float(RAND_MAX));
   287→                    float y_ = a - a / 2 + a / 2 * (rand_r(&seed) / float(RAND_MAX));
   288→                    sub_pixel = vec3 ((-0.5 + 0.5 / srceen_width + (x + x_) * 1.0 / srceen_width), (-0.5 + 0.5 / screen_height + (y + y_) * 1.0 / screen_height), -2.0f);
   289→                    d = vec3(focal_x - sub_pixel[0], focal_y - sub_pixel[1], focal - sub_pixel[2]);
   290→                    d = R * d;
   291→
   292→                    if (closest_intersection(sub_pixel, d, triangles, intersection, mirror_intersec, 0))
   293→                    {
