   310→
   311→                    anti_aliasing[j][i][area] = anti_aliasing[j][i][area] + original_img[width][height];
   312→                    width++;
   313→                }
   314→                height++;
   315→            }
   316→
   317→            anti_aliasing[j][i][area] = anti_aliasing[j][i][area] / vec3(9.0f, 9.0f, 9.0f);
