   327→bool closest_intersection(const vec3& start, const vec3& dir, const vector<Triangle>& triangles, Intersection& cloestIntersection, Intersection& mirIntersection, int light)
   328→{
   329→
   330→    bool flag = false;
   331→    float min = 0.0;
   332→    int triangle_index, ignore = 1;
