   339→        ignore = 0;
   340→
   341→    for (size_t i = 0; i < triangles.size(); i++)
   342→    {
   343→        v0 = triangles[i].v0;
   344→        v1 = triangles[i].v1;
   345→        v2 = triangles[i].v2;
   346→
   347→        if (ignore == 1 && light == 0)
   348→        {
   349→            if (i <= 9)
   350→            {
   351→                float t_hit, u_hit, v_hit;
   352→                if (RayTriangleIntersection(start, dir, v0, v1, v2, t_hit, u_hit, v_hit) && t_hit > 0.03f)
   353→                {
   354→                    if (!flag)
   355→                    {
   356→                        min = t_hit;
   357→                        triangle_index = i;
   358→                    }
   359→                    flag = true;
   360→                    if (min > t_hit)
   361→                    {
   362→                        min = t_hit;
   363→                        triangle_index = i;
   364→                    }
   365→                }
   366→            }
   367→        }
   368→        else if (ignore == 0 || light == 1)
   369→        {
   370→            float t_hit, u_hit, v_hit;
   371→            if (RayTriangleIntersection(start, dir, v0, v1, v2, t_hit, u_hit, v_hit) && t_hit > 0.03f)
   372→            {
   373→                if (!flag)
   374→                {
   375→                    min = t_hit;
   376→                    triangle_index = i;
   377→                }
   378→                flag = true;
   379→                if (min > t_hit)
   380→                {
   381→                    min = t_hit;
   382→                    triangle_index = i;
   383→                }
   384→            }
   385→        }
   386→    }
   387→
   388→    if (flag)
   389→    {
   390→        cloestIntersection.position = start + min * dir;
   391→        cloestIntersection.distance = min;
   392→        cloestIntersection.triangle_index = triangle_index;
   393→        if (triangle_index == 4 || triangle_index == 5)
   394→        {
   395→            reflect_position = start + min * dir;
   396→            reflect_dir = vec3(-dir[0], dir[1], dir[2]);
   397→            if (mirror_intersection(reflect_position, reflect_dir, triangles, reflect_intersec))
   398→            {
   399→                cloestIntersection.colour = reflect_intersec.colour;
   400→
   401→                mirIntersection.triangle_index = reflect_intersec.triangle_index;
   402→                mirIntersection.position = reflect_intersec.position;
   403→                mirIntersection.distance = reflect_intersec.distance;
   404→            }
   405→            cloestIntersection.is_mirror = true;
   406→        }
   407→        else
   408→        {
   409→            mirIntersection.triangle_index = triangle_index;
   410→            mirIntersection.position = start + min * dir;
   411→            mirIntersection.distance = min;
   412→            cloestIntersection.colour = triangles[triangle_index].color;
   413→            cloestIntersection.is_mirror = false;
   414→        }
   415→        return true;
   416→    }
   417→    else
