    91→    float3 qvec = cross(tvec, e1);
    92→    float  v    = dot(dir, qvec) * invDet;
    93→    if (v < 0.0f || u + v > 1.0f) return false;
    94→
    95→    t = dot(e2, qvec) * invDet;
    96→    return t > 0.0f;
