141→                                 int    id,
142→                                 constant GPUTriangle* triangles,
143→                                 int triangle_count)
144→{
145→    int lo = max(0,              id - 2);
146→    int hi = min(triangle_count, id + 3);
147→
148→    for (int i = lo; i < hi; ++i) {
149→        float t = 0.0f;
150→        if (ray_triangle_intersect(orig, dir,
151→                                   triangles[i].v0.xyz,
152→                                   triangles[i].v1.xyz,
153→                                   triangles[i].v2.xyz,
154→                                   t))
155→        {
156→            if (t > 0.0f) return true;
157→        }
158→    }
159→    return false;
160→}
161→
162→// ---------------------------------------------------------------------------
163→// closest_intersect_gpu
164→// ---------------------------------------------------------------------------
165→inline GPUIntersection closest_intersect_gpu(float3 orig,
166→                                             float3 dir,
167→                                             constant GPUTriangle* triangles,
168→                                             int triangle_count,
169→                                             int light,              // 0 = normal, 1 = shadow ray
170→                                             constant RenderUniforms& uni)
171→{
172→    GPUIntersection result;
173→    result.distance       = 1e30f;
174→    result.triangle_index = -1;
175→    result.colour         = float3(0.0f);
176→    result.is_mirror      = false;
177→    result.position       = float3(0.0f);
178→
179→    // --- Triangle loop ---
180→    // Always test all triangles for primary and shadow rays.
181→    // The original CPU front-plane test caused seam blurring: AA jitter made
182→    // some sub-samples hit the front plane (ignore=0, all 30 tris) and others
183→    // miss it (ignore=1, only 10 tris), giving inconsistent results per pixel.
184→    for (int i = 0; i < triangle_count; ++i) {
185→        float t = 0.0f;
186→        if (ray_triangle_intersect(orig, dir,
187→                                   triangles[i].v0.xyz,
188→                                   triangles[i].v1.xyz,
189→                                   triangles[i].v2.xyz,
190→                                   t))
191→        {
192→            if (t > 0.03f && t < result.distance) {
193→                result.distance       = t;
194→                result.triangle_index = i;
195→                result.position       = orig + dir * t;
196→            }
197→        }
198→    }
199→
200→    // --- Post-process hit ---
201→    if (result.triangle_index >= 0) {
202→        int idx = result.triangle_index;
203→
204→        if (idx == 4 || idx == 5) {
205→            // Mirror surface: reflect and re-trace
206→            float3 reflect_dir = float3(-dir.x, dir.y, dir.z);
207→            GPUIntersection mirror_hit = mirror_intersect_gpu(result.position,
208→                                                              reflect_dir,
209→                                                              triangles,
210→                                                              triangle_count);
211→            result.colour    = mirror_hit.colour;
212→            result.is_mirror = true;
213→        } else {
214→            result.colour    = triangles[idx].color.xyz;
215→            result.is_mirror = false;
216→        }
217→    }
218→
219→    return result;
220→}
221→
222→// ---------------------------------------------------------------------------
223→// direct_light_gpu
224→// ---------------------------------------------------------------------------
225→inline float3 direct_light_gpu(GPUIntersection        point,
226→                                constant GPUTriangle*  triangles,
227→                                int                    triangle_count,
228→                                constant RenderUniforms& uni,
229→                                thread uint&           seed)
230→{
231→    int    idx           = point.triangle_index;
232→    float3 surface_light = uni.light_pos.xyz - point.position;
233→    float  r             = length(surface_light);
234→
235→    float  result_dot    = dot(surface_light, triangles[idx].normal.xyz);
236→    float  area_divisor  = 4.0f * M_PI_F * r * r;
237→
238→    float3 light_area;
239→    if (result_dot > 0.0f) {
240→        light_area = (result_dot / area_divisor) * uni.light_colour.xyz;
241→    } else {
242→        light_area = float3(0.0f);
243→    }
244→
245→    // --- Shadow branch ---
246→    bool do_shadow_check = true;
247→    if (uni.light_pos.y < -0.20f) {
248→        // Only cast shadow rays from surfaces above the threshold
249→        do_shadow_check = (point.position.y >= -0.20f);
250→    }
251→
252→    if (do_shadow_check) {
253→        GPUIntersection occluder = closest_intersect_gpu(point.position,
254→                                                         surface_light,
255→                                                         triangles,
256→                                                         triangle_count,
257→                                                         1,  // light ray
258→                                                         uni);
259→
260→        // CPU checks: r > length(dis) where dis = t * surface_light
261→        // → r > t * r → 1.0 > t
262→        // i.e. occluder parameter t must be < 1.0 to be between surface and light
263→        bool blocked = (occluder.triangle_index >= 0) &&
264→                       (occluder.distance < 1.0f)     &&
265→                       (result_dot > 0.0f)             &&
266→                       (occluder.triangle_index != idx);
267→
268→        if (blocked) {
269→            light_area = float3(0.0f);
270→
271→            // Soft shadow: 10 jittered samples
272→            // Use occluder.triangle_index (not idx) to search around the occluder,
273→            // matching CPU: shadow_intersection(point.position, direction, inter.triangle_index, ...)
274→            int occluder_idx = occluder.triangle_index;
275→            float3 soft = float3(0.0f);
276→            for (int s = 0; s < 10; ++s) {
277→                float jx = rand_float(seed) * 2.0f - 1.0f;
278→                float jy = rand_float(seed) * 2.0f - 1.0f;
279→                float jz = rand_float(seed) * 2.0f - 1.0f;
280→
281→                float3 jitter_dir = surface_light + float3(0.03f * jx,
282→                                                           0.03f * jy,
283→                                                           0.03f * jz);
284→                if (shadow_intersect_gpu(point.position, jitter_dir,
285→                                         occluder_idx, triangles, triangle_count)) {
286→                    // fully in shadow — add nothing
287→                } else {
288→                    soft += triangles[idx].color.xyz;
289→                }
290→            }
291→            light_area += soft / 10.0f;
292→        }
293→    }
294→
295→    return light_area;
296→}
297→
298→// ---------------------------------------------------------------------------
299→// Kernel
300→// ---------------------------------------------------------------------------
301→kernel void raytracer_kernel(
302→    uint3                          gid            [[thread_position_in_grid]],
303→    constant GPUTriangle*          triangles      [[buffer(0)]],
304→    constant RenderUniforms&       uni            [[buffer(1)]],
305→    device   float4*               output_buffer  [[buffer(2)]])
306→{
307→    uint x          = gid.x;
308→    uint y          = gid.y;
309→    uint sample_idx = gid.z;
310→
311→    int sw = uni.screen_width;
312→    int sh = uni.screen_height;
313→
314→    if (x >= (uint)sw || y >= (uint)sh || sample_idx >= 9u) return;
315→
316→    // --- Seed ---
317→    uint seed = (x * 1000u + y) * 9u + sample_idx + 1u;
318→
319→    // --- Rotation matrix (yaw around Y axis) ---
320→    // GLM mat3 col-major: col0=(cos,0,-sin), col1=(0,1,0), col2=(sin,0,cos)
321→    // R*d = float3(cos*d.x + sin*d.z,  d.y,  -sin*d.x + cos*d.z)
322→    float yaw     = uni.yaw;
323→    float cos_yaw = cos(yaw);
324→    float sin_yaw = sin(yaw);
325→
326→    // --- Primary ray focal point ---
327→    float sw_f = float(sw);
328→    float sh_f = float(sh);
329→
330→    float focal_x = (-0.5f + 0.5f / sw_f + float(x) / sw_f)
331→                    * (uni.focal - uni.camera_pos.z) / uni.f;
332→    float focal_y = (-0.5f + 0.5f / sh_f + float(y) / sh_f)
333→                    * (uni.focal - uni.camera_pos.z) / uni.f;
334→
335→    // --- Anti-aliasing sub-sample grid (3×3, stratified jitter) ---
336→    // Divide [-8, 8] into 3 equal strata of width 16/3 each.
337→    // Each sample falls uniformly within its stratum — no gaps, no overlap.
338→    // Total spread stays ±8 pixels so depth-of-field effect is unchanged.
339→    int a_idx = int(sample_idx) / 3;   // 0, 1, 2
340→    int b_idx = int(sample_idx) % 3;   // 0, 1, 2
341→
342→    float x_ = -8.0f + (float(b_idx) + rand_float(seed)) * (16.0f / 3.0f);
343→    float y_ = -8.0f + (float(a_idx) + rand_float(seed)) * (16.0f / 3.0f);
344→
345→    // --- Sub-pixel position ---
346→    float3 sub_pixel = float3(
347→        -0.5f + 0.5f / sw_f + (float(x) + x_) / sw_f,
348→        -0.5f + 0.5f / sh_f + (float(y) + y_) / sh_f,
349→        -2.0f
350→    );
351→
352→    // --- Ray direction (before rotation) ---
353→    float3 d_local = float3(focal_x - sub_pixel.x,
354→                            focal_y - sub_pixel.y,
355→                            uni.focal - sub_pixel.z);
356→
357→    // Apply Y-axis rotation: R*d
358→    float3 d = float3(
359→         cos_yaw * d_local.x + sin_yaw * d_local.z,
360→         d_local.y,
361→        -sin_yaw * d_local.x + cos_yaw * d_local.z
362→    );
363→
364→    // --- Trace primary ray ---
365→    // Ray origin is sub_pixel (lens sample point at z=-2), NOT camera_pos (z=-3)
366→    // This matches the CPU code: closest_intersection(sub_pixel, d, ...)
367→    GPUIntersection intersection = closest_intersect_gpu(
368→        sub_pixel, d,
369→        triangles, uni.triangle_count,
370→        0, uni);
371→
372→    float3 pixel_colour = float3(0.0f);
373→
374→    if (intersection.triangle_index >= 0) {
375→        float3 light_area = direct_light_gpu(intersection,
376→                                             triangles,
377→                                             uni.triangle_count,
378→                                             uni,
379→                                             seed);
380→
381→        if (intersection.is_mirror) {
382→            // Mirror: also light the reflected surface and blend
383→            int mirror_idx = intersection.triangle_index;
384→
385→            // Build a temporary intersection at the mirror hit to light it
386→            // We already have the reflected colour in intersection.colour,
387→            // but we need a GPUIntersection pointing at the reflected surface.
388→            // Re-trace the reflected ray to get the proper surface intersection.
389→            float3 reflect_dir = float3(-d.x, d.y, d.z);
390→            GPUIntersection mirror_isec = mirror_intersect_gpu(
391→                intersection.position, reflect_dir,
392→                triangles, uni.triangle_count);
393→
394→            float3 mirror_shadow = float3(0.0f);
395→            if (mirror_isec.triangle_index >= 0) {
396→                mirror_shadow = direct_light_gpu(mirror_isec,
397→                                                 triangles,
398→                                                 uni.triangle_count,
399→                                                 uni,
400→                                                 seed);
401→            }
402→
403→            light_area = 0.5f * (uni.indirect_light.xyz +
404→                                 (light_area + mirror_shadow) / 2.0f);
405→        } else {
406→            light_area = 0.5f * (uni.indirect_light.xyz + light_area);
407→        }
408→
409→        pixel_colour = light_area * intersection.colour;
410→    }
411→
412→    // --- Write output ---
413→    uint out_idx = (y * uint(sw) + x) * 9u + sample_idx;
414→    output_buffer[out_idx] = float4(pixel_colour, 1.0f);
415→}
