#ifndef TEST_MODEL_CORNEL_BOX_H
#define TEST_MODEL_CORNEL_BOX_H

// Defines a simple test model: The Cornel Box

#include <glm/glm.hpp>
#include <vector>

// Used to describe a triangular surface:
class Triangle
{
public:
	glm::vec3 v0;
	glm::vec3 v1;
	glm::vec3 v2;
	glm::vec3 normal;
	glm::vec3 color;
	float roughness;
	float metalness;

	Triangle( glm::vec3 v0, glm::vec3 v1, glm::vec3 v2, glm::vec3 color,
	          float roughness = 0.5f, float metalness = 0.0f )
		: v0(v0), v1(v1), v2(v2), color(color),
		  roughness(roughness), metalness(metalness)
	{
		ComputeNormal();
	}

	void ComputeNormal()
	{
		glm::vec3 e1 = v1 - v0;
		glm::vec3 e2 = v2 - v0;
		normal = glm::normalize( glm::cross( e2, e1 ) );
	}
};

// Loads the Cornell Box. It is scaled to fill the volume:
// -1 <= x <= +1
// -1 <= y <= +1
// -1 <= z <= +1
inline void LoadTestModel( std::vector<Triangle>& triangles )
{
	using glm::vec3;

	// Defines colors:
	vec3 red(    0.75f, 0.15f, 0.15f );
	vec3 yellow( 0.75f, 0.75f, 0.15f );
	vec3 green(  0.15f, 0.75f, 0.15f );
	vec3 cyan(   0.15f, 0.75f, 0.75f );
	vec3 blue(   0.15f, 0.15f, 0.75f );
	vec3 purple( 0.75f, 0.15f, 0.75f );
	vec3 white(  0.75f, 0.75f, 0.75f );

	triangles.clear();
	triangles.reserve( 5 * 2 * 3 );

	// ---------------------------------------------------------------------------
	// Room

	float L = 555;			// Length of Cornell Box side.

	vec3 A(L, 0, 0);
	vec3 B(0, 0, 0);
	vec3 C(L, 0, L);
	vec3 D(0, 0, L);

	vec3 E(L, L, 0);
	vec3 F(0, L, 0);
	vec3 G(L, L, L);
	vec3 H(0, L, L);

	// Floor:
	triangles.push_back( Triangle( C, B, A, green, 0.9f, 0.0f ) );
	triangles.push_back( Triangle( C, D, B, green, 0.9f, 0.0f ) );

	// Left wall
	triangles.push_back( Triangle( A, E, C, purple, 0.9f, 0.0f ) );
	triangles.push_back( Triangle( C, E, G, purple, 0.9f, 0.0f ) );

	// Right wall (mirror surface)
	triangles.push_back( Triangle( F, B, D, yellow, 0.05f, 1.0f ) );
	triangles.push_back( Triangle( H, F, D, yellow, 0.05f, 1.0f ) );

	// Ceiling
	triangles.push_back( Triangle( E, F, G, cyan, 0.9f, 0.0f ) );
	triangles.push_back( Triangle( F, H, G, cyan, 0.9f, 0.0f ) );

	// Back wall
	triangles.push_back( Triangle( G, D, C, white, 0.9f, 0.0f ) );
	triangles.push_back( Triangle( G, H, D, white, 0.9f, 0.0f ) );

	// ---------------------------------------------------------------------------
	// Short block

	A = vec3(290, 0, 114);
	B = vec3(130, 0, 65);
	C = vec3(240, 0, 272);
	D = vec3( 82, 0, 225);

	E = vec3(290, 165, 114);
	F = vec3(130, 165, 65);
	G = vec3(240, 165, 272);
	H = vec3( 82, 165, 225);

	// Front
	triangles.push_back( Triangle(E, B, A, red) );
	triangles.push_back( Triangle(E, F, B, red) );

	// Front
	triangles.push_back( Triangle(F, D, B, red) );
	triangles.push_back( Triangle(F, H, D, red) );

	// BACK
	triangles.push_back( Triangle(H, C, D, red) );
	triangles.push_back( Triangle(H, G, C, red) );

	// LEFT
	triangles.push_back( Triangle(G, E, C, red) );
	triangles.push_back( Triangle(E, A, C, red) );

	// TOP
	triangles.push_back( Triangle(G, F, E, red) );
	triangles.push_back( Triangle(G, H, F, red) );

	// ---------------------------------------------------------------------------
	// Tall block

	A = vec3(423, 0, 247);
	B = vec3(265, 0, 296);
	C = vec3(472, 0, 406);
	D = vec3(314, 0, 456);

	E = vec3(423, 330, 247);
	F = vec3(265, 330, 296);
	G = vec3(472, 330, 406);
	H = vec3(314, 330, 456);

	// Front
	triangles.push_back( Triangle(E, B, A, blue) );
	triangles.push_back( Triangle(E, F, B, blue) );

	// Front
	triangles.push_back( Triangle(F, D, B, blue) );
	triangles.push_back( Triangle(F, H, D, blue) );

	// BACK
	triangles.push_back( Triangle(H, C, D, blue) );
	triangles.push_back( Triangle(H, G, C, blue) );

	// LEFT
	triangles.push_back( Triangle(G, E, C, blue) );
	triangles.push_back( Triangle(E, A, C, blue) );

	// TOP
	triangles.push_back( Triangle(G, F, E, blue) );
	triangles.push_back( Triangle(G, H, F, blue) );


	// ----------------------------------------------
	// Scale to the volume [-1,1]^3

	for ( size_t i = 0; i < triangles.size(); ++i )
	{
		triangles[i].v0 *= 2 / L;
		triangles[i].v1 *= 2 / L;
		triangles[i].v2 *= 2 / L;

		triangles[i].v0 -= vec3(1, 1, 1);
		triangles[i].v1 -= vec3(1, 1, 1);
		triangles[i].v2 -= vec3(1, 1, 1);

		triangles[i].v0.x *= -1;
		triangles[i].v1.x *= -1;
		triangles[i].v2.x *= -1;

		triangles[i].v0.y *= -1;
		triangles[i].v1.y *= -1;
		triangles[i].v2.y *= -1;

		triangles[i].ComputeNormal();
	}
}

#endif

