/* PBR Helper Functions                                                        */

// GGX Normal Distribution Function
inline float distribution_ggx(const vec3& N, const vec3& H, float roughness)
{
    float a  = roughness * roughness;
    float a2 = a * a;
    float NdotH  = glm::max(glm::dot(N, H), 0.0f);
    float NdotH2 = NdotH * NdotH;

    float denom = NdotH2 * (a2 - 1.0f) + 1.0f;
    denom = (float)M_PI * denom * denom;

    return a2 / glm::max(denom, 0.0001f);
}

// Schlick-GGX Geometry function (single direction)
inline float geometry_schlick_ggx(float NdotX, float roughness)
{
    float r = roughness + 1.0f;
    float k = (r * r) / 8.0f;
    return NdotX / (NdotX * (1.0f - k) + k);
}

// Smith's method for geometry (both directions)
inline float geometry_smith(const vec3& N, const vec3& V, const vec3& L, float roughness)
{
    float NdotV = glm::max(glm::dot(N, V), 0.0f);
    float NdotL = glm::max(glm::dot(N, L), 0.0f);
    return geometry_schlick_ggx(NdotV, roughness) * geometry_schlick_ggx(NdotL, roughness);
}

// Schlick Fresnel approximation
inline vec3 fresnel_schlick(float cos_theta, const vec3& F0)
{
    float t = 1.0f - cos_theta;
    float t2 = t * t;
    float t5 = t2 * t2 * t;
    return F0 + (vec3(1.0f) - F0) * t5;
}

// Reinhard tone mapping + gamma correction
inline vec3 tonemap_gamma(const vec3& color)
{
    // Reinhard
    vec3 mapped = color / (vec3(1.0f) + color);
    // Gamma correction (linear -> sRGB)
    float inv_gamma = 1.0f / 2.2f;
    return vec3(powf(mapped.x, inv_gamma), powf(mapped.y, inv_gamma), powf(mapped.z, inv_gamma));
}

// Generate a random direction in the hemisphere around normal N
inline vec3 random_hemisphere(const vec3& N, unsigned int& seed)
{
    // Generate random direction on unit sphere
    float u1 = rand_r(&seed) / float(RAND_MAX);
    float u2 = rand_r(&seed) / float(RAND_MAX);
    float z = u1;
    float r = sqrtf(1.0f - z * z);
    float phi = 2.0f * (float)M_PI * u2;
    vec3 random_dir(r * cosf(phi), r * sinf(phi), z);

    // Build tangent frame
    vec3 up = (fabsf(N.y) < 0.999f) ? vec3(0, 1, 0) : vec3(1, 0, 0);
    vec3 tangent = glm::normalize(glm::cross(up, N));
    vec3 bitangent = glm::cross(N, tangent);

    return glm::normalize(tangent * random_dir.x + bitangent * random_dir.y + N * random_dir.z);
}

inline bool RayTriangleIntersection(const vec3& orig,
                                    const vec3& dir,
                                    const vec3& v0,
                                    const vec3& v1,
                                    const vec3& v2,
                                    float& t,
                                    float& u,
                                    float& v)
{
    const float EPSILON = 1e-6f;
    vec3 e1 = v1 - v0;
    vec3 e2 = v2 - v0;
    vec3 pvec = glm::cross(dir, e2);
    float det = glm::dot(e1, pvec);
    if (fabs(det) < EPSILON)
        return false;

    float invDet = 1.0f / det;
    vec3 tvec = orig - v0;
    u = glm::dot(tvec, pvec) * invDet;
    if (u < 0.0f || u > 1.0f)
        return false;

    vec3 qvec = glm::cross(tvec, e1);
    v = glm::dot(dir, qvec) * invDet;
    if (v < 0.0f || u + v > 1.0f)
        return false;

    t = glm::dot(e2, qvec) * invDet;
    return t > 0.0f;
}


