 99→// ---------------------------------------------------------------------------
100→// mirror_intersect_gpu
101→// Scans all triangles and returns the closest hit (t > 0.03).
102→// ---------------------------------------------------------------------------
103→inline GPUIntersection mirror_intersect_gpu(float3 orig,
104→                                            float3 dir,
105→                                            constant GPUTriangle* triangles,
106→                                            int triangle_count)
107→{
108→    GPUIntersection result;
109→    result.distance       = 1e30f;
110→    result.triangle_index = -1;
111→    result.colour         = float3(0.0f);
112→    result.is_mirror      = false;
113→    result.position       = float3(0.0f);
114→
115→    for (int i = 0; i < triangle_count; ++i) {
116→        float t = 0.0f;
117→        if (ray_triangle_intersect(orig, dir,
118→                                   triangles[i].v0.xyz,
119→                                   triangles[i].v1.xyz,
120→                                   triangles[i].v2.xyz,
121→                                   t))
122→        {
123→            if (t > 0.001f && t < result.distance) {
124→                result.distance       = t;
125→                result.triangle_index = i;
126→                result.position       = orig + dir * t;
127→                result.colour         = triangles[i].color.xyz;
128→            }
129→        }
130→    }
131→
132→    return result;
133→}
