135→// ---------------------------------------------------------------------------
136→// shadow_intersect_gpu
137→// Tests a narrow band of triangles around `id` for any occlusion.
138→// ---------------------------------------------------------------------------
139→inline bool shadow_intersect_gpu(float3 orig,
140→                                 float3 dir,
141→                                 int    id,
142→                                 constant GPUTriangle* triangles,
143→                                 int triangle_count)
144→{
145→    int lo = max(0,              id - 2);
146→    int hi = min(triangle_count, id + 3);
147→
148→    for (int i = lo; i < hi; ++i) {
149→        float t = 0.0f;
150→        if (ray_triangle_intersect(orig, dir,
151→                                   triangles[i].v0.xyz,
152→                                   triangles[i].v1.xyz,
153→                                   triangles[i].v2.xyz,
154→                                   t))
155→        {
156→            if (t > 0.0f) return true;
157→        }
158→    }
159→    return false;
160→}
