298→// ---------------------------------------------------------------------------
299→// Kernel
300→// ---------------------------------------------------------------------------
301→kernel void raytracer_kernel(
302→    uint3                          gid            [[thread_position_in_grid]],
303→    constant GPUTriangle*          triangles      [[buffer(0)]],
304→    constant RenderUniforms&       uni            [[buffer(1)]],
305→    device   float4*               output_buffer  [[buffer(2)]])
306→{
307→    uint x          = gid.x;
308→    uint y          = gid.y;
309→    uint sample_idx = gid.z;
310→
311→    int sw = uni.screen_width;
312→    int sh = uni.screen_height;
313→
314→    if (x >= (uint)sw || y >= (uint)sh || sample_idx >= 9u) return;
315→
316→    // --- Seed ---
317→    uint seed = (x * 1000u + y) * 9u + sample_idx + 1u;
318→
319→    // --- Rotation matrix (yaw around Y axis) ---
320→    // GLM mat3 col-major: col0=(cos,0,-sin), col1=(0,1,0), col2=(sin,0,cos)
321→    // R*d = float3(cos*d.x + sin*d.z,  d.y,  -sin*d.x + cos*d.z)
322→    float yaw     = uni.yaw;
323→    float cos_yaw = cos(yaw);
324→    float sin_yaw = sin(yaw);
325→
326→    // --- Primary ray focal point ---
327→    float sw_f = float(sw);
328→    float sh_f = float(sh);
329→
330→    float focal_x = (-0.5f + 0.5f / sw_f + float(x) / sw_f)
331→                    * (uni.focal - uni.camera_pos.z) / uni.f;
332→    float focal_y = (-0.5f + 0.5f / sh_f + float(y) / sh_f)
333→                    * (uni.focal - uni.camera_pos.z) / uni.f;
334→
335→    // --- Anti-aliasing sub-sample grid (3×3, stratified jitter) ---
336→    // Divide [-8, 8] into 3 equal strata of width 16/3 each.
337→    // Each sample falls uniformly within its stratum — no gaps, no overlap.
338→    // Total spread stays ±8 pixels so depth-of-field effect is unchanged.
339→    int a_idx = int(sample_idx) / 3;   // 0, 1, 2
340→    int b_idx = int(sample_idx) % 3;   // 0, 1, 2
341→
342→    float x_ = -8.0f + (float(b_idx) + rand_float(seed)) * (16.0f / 3.0f);
343→    float y_ = -8.0f + (float(a_idx) + rand_float(seed)) * (16.0f / 3.0f);
344→
345→    // --- Sub-pixel position ---
346→    float3 sub_pixel = float3(
347→        -0.5f + 0.5f / sw_f + (float(x) + x_) / sw_f,
348→        -0.5f + 0.5f / sh_f + (float(y) + y_) / sh_f,
349→        -2.0f
350→    );
351→
352→    // --- Ray direction (before rotation) ---
353→    float3 d_local = float3(focal_x - sub_pixel.x,
354→                            focal_y - sub_pixel.y,
355→                            uni.focal - sub_pixel.z);
356→
357→    // Apply Y-axis rotation: R*d
358→    float3 d = float3(
359→         cos_yaw * d_local.x + sin_yaw * d_local.z,
360→         d_local.y,
361→        -sin_yaw * d_local.x + cos_yaw * d_local.z
362→    );
363→
364→    // --- Trace primary ray ---
365→    // Ray origin is sub_pixel (lens sample point at z=-2), NOT camera_pos (z=-3)
366→    // This matches the CPU code: closest_intersection(sub_pixel, d, ...)
367→    GPUIntersection intersection = closest_intersect_gpu(
368→        sub_pixel, d,
369→        triangles, uni.triangle_count,
370→        0, uni);
371→
372→    float3 pixel_colour = float3(0.0f);
373→
374→    if (intersection.triangle_index >= 0) {
375→        float3 light_area = direct_light_gpu(intersection,
376→                                             triangles,
377→                                             uni.triangle_count,
378→                                             uni,
379→                                             seed);
380→
381→        if (intersection.is_mirror) {
382→            // Mirror: also light the reflected surface and blend
383→            int mirror_idx = intersection.triangle_index;
384→
385→            // Build a temporary intersection at the mirror hit to light it
386→            // We already have the reflected colour in intersection.colour,
387→            // but we need a GPUIntersection pointing at the reflected surface.
388→            // Re-trace the reflected ray to get the proper surface intersection.
389→            float3 reflect_dir = float3(-d.x, d.y, d.z);
390→            GPUIntersection mirror_isec = mirror_intersect_gpu(
391→                intersection.position, reflect_dir,
392→                triangles, uni.triangle_count);
393→
394→            float3 mirror_shadow = float3(0.0f);
395→            if (mirror_isec.triangle_index >= 0) {
396→                mirror_shadow = direct_light_gpu(mirror_isec,
397→                                                 triangles,
398→                                                 uni.triangle_count,
399→                                                 uni,
400→                                                 seed);
401→            }
402→
403→            light_area = 0.5f * (uni.indirect_light.xyz +
404→                                 (light_area + mirror_shadow) / 2.0f);
405→        } else {
406→            light_area = 0.5f * (uni.indirect_light.xyz + light_area);
407→        }
408→
409→        pixel_colour = light_area * intersection.colour;
410→    }
411→
412→    // --- Write output ---
413→    uint out_idx = (y * uint(sw) + x) * 9u + sample_idx;
414→    output_buffer[out_idx] = float4(pixel_colour, 1.0f);
415→}
