    switch (area)
    {
    case 0: x_value = 0;                y_value = 0;                break;
    case 1: x_value = SCREEN_WIDTH / 3; y_value = 0;                break;
    case 2: x_value = SCREEN_WIDTH / 3 * 2; y_value = 0;           break;
    case 3: x_value = 0;                y_value = SCREEN_HEIGHT / 3; break;
    case 4: x_value = SCREEN_WIDTH / 3; y_value = SCREEN_HEIGHT / 3; break;
    case 5: x_value = SCREEN_WIDTH / 3 * 2; y_value = SCREEN_HEIGHT / 3; break;
    case 6: x_value = 0;                y_value = SCREEN_HEIGHT / 3 * 2; break;
    case 7: x_value = SCREEN_WIDTH / 3; y_value = SCREEN_HEIGHT / 3 * 2; break;
    case 8: x_value = SCREEN_WIDTH / 3 * 2; y_value = SCREEN_HEIGHT / 3 * 2; break;
    default:
        printf("ERROR!\n");
        break;
    }

    for (int i = 0; i < SCREEN_HEIGHT / 3; i++)
    {
        for (int j = 0; j < SCREEN_WIDTH / 3; j++)
        {
            x = j + x_value;
            y = i + y_value;

            focal_x = (-0.5 + 0.5 / srceen_width + x * 1.0 / srceen_width) * (focal - camera_pos[2]) / f;
            focal_y = (-0.5 + 0.5 / screen_height + y * 1.0 / screen_height) * (focal - camera_pos[2]) / f;
            height = 0;

            for (int a = -8; a < 9; a = a + 8)
            {
                int width = 0;
                for (int b = -8; b < 9; b = b + 8)
                {
                    float x_ = b - b / 2 + b / 2 * (rand_r(&seed) / float(RAND_MAX));
                    float y_ = a - a / 2 + a / 2 * (rand_r(&seed) / float(RAND_MAX));
                    sub_pixel = vec3 ((-0.5 + 0.5 / srceen_width + (x + x_) * 1.0 / srceen_width), (-0.5 + 0.5 / screen_height + (y + y_) * 1.0 / screen_height), -2.0f);
                    d = vec3(focal_x - sub_pixel[0], focal_y - sub_pixel[1], focal - sub_pixel[2]);
                    d = R * d;

                    // View direction is from hit point back toward camera (negated ray direction)
                    vec3 view_dir = -glm::normalize(d);

                    if (closest_intersection(sub_pixel, d, triangles, intersection, mirror_intersec, 0))
                    {
                        light_area = direct_light(intersection, view_dir, seed);

                        // Compute ambient occlusion
                        vec3 N_hit = triangles[intersection.triangle_index].normal;
                        float ao = compute_ao(intersection.position, N_hit, seed);
                        vec3 ambient = ao * 0.3f * intersection.colour;

                        if (intersection.is_mirror)
                        {
                            mirror_shadow = direct_light(mirror_intersec, view_dir, seed);
                            // Compute AO for reflected point too
                            vec3 N_mir = triangles[mirror_intersec.triangle_index].normal;
                            float ao_mir = compute_ao(mirror_intersec.position, N_mir, seed);
                            vec3 ambient_mir = ao_mir * 0.3f * mirror_intersec.colour;
                            light_area = ambient + 0.5f * (light_area + mirror_shadow);
                        }
                        else
                        {
                            light_area = ambient + light_area;
                        }
                        pixel_colour = light_area;

                        original_img[width][height] = pixel_colour;
                    }
                    else
                        original_img[width][height] = black;

                    anti_aliasing[j][i][area] = anti_aliasing[j][i][area] + original_img[width][height];
                    width++;
                }
                height++;
            }

            anti_aliasing[j][i][area] = anti_aliasing[j][i][area] / vec3(9.0f, 9.0f, 9.0f);

            // Apply tone mapping and gamma correction
            anti_aliasing[j][i][area] = tonemap_gamma(anti_aliasing[j][i][area]);

            PutPixelSDL(screen, x, y, anti_aliasing[j][i][area]);
            anti_aliasing[j][i][area] = black;
        }
    }
    return NULL;
}

bool closest_intersection(const vec3& start, const vec3& dir, const vector<Triangle>& triangles, Intersection& cloestIntersection, Intersection& mirIntersection, int light)
{

    bool flag = false;
    float min = 0.0;
    int triangle_index, ignore = 1;
    vec3 v0, v1, v2;
    vec3 reflect_position, reflect_dir;
    Intersection reflect_intersec;

    float t_front, u_front, v_front;
    if (RayTriangleIntersection(start, dir, FRONT_V0, FRONT_V1, FRONT_V2, t_front, u_front, v_front))
        ignore = 0;

    for (size_t i = 0; i < triangles.size(); i++)
    {
        v0 = triangles[i].v0;
        v1 = triangles[i].v1;
        v2 = triangles[i].v2;

        if (ignore == 1 && light == 0)
        {
            if (i <= 9)
            {
                float t_hit, u_hit, v_hit;
                if (RayTriangleIntersection(start, dir, v0, v1, v2, t_hit, u_hit, v_hit) && t_hit > 0.03f)
                {
                    if (!flag)
                    {
                        min = t_hit;
                        triangle_index = i;
                    }
                    flag = true;
                    if (min > t_hit)
                    {
                        min = t_hit;
                        triangle_index = i;
                    }
                }
            }
        }
        else if (ignore == 0 || light == 1)
        {
            float t_hit, u_hit, v_hit;
            if (RayTriangleIntersection(start, dir, v0, v1, v2, t_hit, u_hit, v_hit) && t_hit > 0.03f)
            {
                if (!flag)
                {
                    min = t_hit;
                    triangle_index = i;
                }
                flag = true;
                if (min > t_hit)
                {
                    min = t_hit;
                    triangle_index = i;
                }
            }
        }
    }

    if (flag)
    {
        cloestIntersection.position = start + min * dir;
        cloestIntersection.distance = min;
        cloestIntersection.triangle_index = triangle_index;
        if (triangle_index == 4 || triangle_index == 5)
        {
            // Physically correct reflection: R = D - 2(D·N)N
            reflect_position = start + min * dir;
            vec3 N = triangles[triangle_index].normal;
            vec3 D_normalized = glm::normalize(dir);
            reflect_dir = D_normalized - 2.0f * glm::dot(D_normalized, N) * N;
            if (mirror_intersection(reflect_position, reflect_dir, triangles, reflect_intersec))
            {
                cloestIntersection.colour = reflect_intersec.colour;

                mirIntersection.triangle_index = reflect_intersec.triangle_index;
                mirIntersection.position = reflect_intersec.position;
                mirIntersection.distance = reflect_intersec.distance;
            }
            cloestIntersection.is_mirror = true;
        }
        else
        {
            mirIntersection.triangle_index = triangle_index;
            mirIntersection.position = start + min * dir;
            mirIntersection.distance = min;
            cloestIntersection.colour = triangles[triangle_index].color;
            cloestIntersection.is_mirror = false;
        }
        return true;
    }
    else
        return false;
}

vec3 direct_light(const Intersection &point, const vec3& view_dir, unsigned int& seed)
{
    vec3 surface_light, dis, shadow_colour;
    float r;
    Intersection inter, shadow_inter, mirIntersection;

    int idx = point.triangle_index;
    vec3 N = triangles[idx].normal;
    vec3 albedo = triangles[idx].color;
    float roughness = triangles[idx].roughness;
    float metalness = triangles[idx].metalness;

    surface_light = light_pos - point.position;
    r = glm::length(surface_light);
    vec3 L = glm::normalize(surface_light);
    vec3 V = glm::normalize(view_dir);
    vec3 H = glm::normalize(V + L);

    float NdotL = glm::max(glm::dot(N, L), 0.0f);

    // PBR: Cook-Torrance specular BRDF
    vec3 F0 = glm::mix(vec3(0.04f), albedo, metalness);
    float D = distribution_ggx(N, H, roughness);
    float G = geometry_smith(N, V, L, roughness);
    vec3 F  = fresnel_schlick(glm::max(glm::dot(H, V), 0.0f), F0);

    vec3 numerator = D * G * F;
    float denominator = 4.0f * glm::max(glm::dot(N, V), 0.0f) * NdotL + 0.0001f;
    vec3 specular = numerator / denominator;

    vec3 kS = F;
    vec3 kD = (vec3(1.0f) - kS) * (1.0f - metalness);

    // Light radiance at this point
    float attenuation = 1.0f / (4.0f * (float)M_PI * r * r);
    vec3 radiance = light_colour * attenuation;

    vec3 light_area = (kD * albedo / (float)M_PI + specular) * radiance * NdotL;

    // --- Shadow testing (same logic as original) ---
    bool do_shadow_check = true;
    if (light_pos[1] < -0.20f)
        do_shadow_check = (point.position[1] >= -0.20f);

    if (do_shadow_check)
    {
        if (closest_intersection(point.position, surface_light, triangles, inter, mirIntersection, 1))
        {
            dis = inter.position - point.position;
            if (r > glm::length(dis) && NdotL > 0.0 && idx != inter.triangle_index)
            {
                // In shadow — soft shadow sampling
                light_area = vec3(0.0, 0.0, 0.0);
                for (int i = 0; i < 10; i++)
                {
                    vec3 direction = surface_light + vec3(0.03f * (((rand_r(&seed) / float(RAND_MAX)) - 0.5f) * 2.0f), 0.03f * (((rand_r(&seed) / float(RAND_MAX)) - 0.5f) * 2.0f), 0.03f * (((rand_r(&seed) / float(RAND_MAX)) - 0.5f) * 2.0f));
                    if (shadow_intersection(point.position, direction, inter.triangle_index, shadow_inter))
                        shadow_colour = vec3(0.0, 0.0, 0.0);
                    else
                        shadow_colour = albedo;

                    light_area = light_area + shadow_colour;
                }
                light_area = light_area / vec3(10.0f, 10.0f, 10.0f);
            }
        }
    }

    return light_area;
}

// Check if a ray is occluded within max_dist (for AO)
bool ao_occluded(const vec3& start, const vec3& dir, float max_dist)
{
    for (size_t i = 0; i < triangles.size(); i++)
    {
        float t_hit, u_hit, v_hit;
        if (RayTriangleIntersection(start, dir, triangles[i].v0, triangles[i].v1, triangles[i].v2, t_hit, u_hit, v_hit)
            && t_hit > 0.01f && t_hit < max_dist)
        {
            return true;
        }
    }
    return false;
}

// Compute ambient occlusion factor (0 = fully occluded, 1 = fully open)
float compute_ao(const vec3& position, const vec3& normal, unsigned int& seed)
{
    const int AO_SAMPLES = 4;
    const float AO_RADIUS = 0.3f;
    int unoccluded = 0;
    for (int i = 0; i < AO_SAMPLES; i++)
    {
        vec3 sample_dir = random_hemisphere(normal, seed);
        if (!ao_occluded(position, sample_dir, AO_RADIUS))
            unoccluded++;
    }
    return (float)unoccluded / (float)AO_SAMPLES;
}

bool shadow_intersection(const vec3& start, const vec3& dir, int triangle_id, Intersection& cloestIntersection)
{
    bool flag = false;
    float t_hit, u_hit, v_hit;

    int i_start = std::max(0, triangle_id - 2);
    int i_end = std::min((int)triangles.size(), triangle_id + 3);

    for (int i = i_start; i < i_end; i++)
    {
        vec3 v0 = triangles[i].v0;
        vec3 v1 = triangles[i].v1;
        vec3 v2 = triangles[i].v2;

        if (RayTriangleIntersection(start, dir, v0, v1, v2, t_hit, u_hit, v_hit) && t_hit > 0.0f)
        {
            flag = true;
            break;
        }
    }

    if (flag)
        return true;
    else
        return false;
}

bool mirror_intersection(const vec3& start, const vec3& dir, const vector<Triangle>& triangles, Intersection& cloestIntersection)
{
    bool flag = false;
    float min = 0.0;
    int triangle_index;
    vec3 v0, v1, v2;

    for (size_t i = 0; i < triangles.size(); i++)
    {
        v0 = triangles[i].v0;
        v1 = triangles[i].v1;
        v2 = triangles[i].v2;

        float t_hit, u_hit, v_hit;
        if (RayTriangleIntersection(start, dir, v0, v1, v2, t_hit, u_hit, v_hit) && t_hit > 0.001f)
        {
            if (!flag)
            {
                min = t_hit;
                triangle_index = i;
            }
            flag = true;
            if (min > t_hit)
            {
                min = t_hit;
                triangle_index = i;
            }
        }
    }

    if (flag)
    {
        cloestIntersection.position = start + min * dir;
        cloestIntersection.distance = min;
        cloestIntersection.triangle_index = triangle_index;
        cloestIntersection.colour = triangles[triangle_index].color;
        return true;
    }
    else
        return false;
}

#include <metal_stdlib>
using namespace metal;

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------
constant int   MAX_TRIANGLES = 30;

// Front-plane test vertices (world space)
constant float3 FRONT_V0 = float3(-0.76f, -0.87f, -1.0f);
constant float3 FRONT_V1 = float3(-0.76f,  1.0f,  -1.0f);
constant float3 FRONT_V2 = float3( 1.31f,  1.0f,  -1.0f);

// ---------------------------------------------------------------------------
// Data structures
// ---------------------------------------------------------------------------
struct GPUTriangle {
    float4 v0;      // w unused
    float4 v1;
    float4 v2;
    float4 normal;
    float4 color;
    float4 material; // x=roughness, y=metalness, z/w unused
};

struct RenderUniforms {
    float4 camera_pos;
    float4 light_pos;
    float4 light_colour;
    float4 indirect_light;
    float4 front_v0;
    float4 front_v1;
    float4 front_v2;
    float  focal;
    float  f;
    float  yaw;
    int    triangle_count;
    int    screen_width;
    int    screen_height;
    float  _pad[2];
};

struct GPUIntersection {
    float3 position;
    float  distance;
    int    triangle_index;
    float3 colour;
    bool   is_mirror;
};

// ---------------------------------------------------------------------------
// LCG random number generator
// ---------------------------------------------------------------------------
inline uint lcg_rand(thread uint& seed) {
    seed = seed * 1664525u + 1013904223u;
    return seed;
}

inline float rand_float(thread uint& seed) {
    return float(lcg_rand(seed)) / 4294967295.0f;
}

// ---------------------------------------------------------------------------
// PBR Helper Functions
// ---------------------------------------------------------------------------

// GGX Normal Distribution Function
inline float distribution_ggx(float3 N, float3 H, float roughness) {
    float a  = roughness * roughness;
    float a2 = a * a;
    float NdotH  = max(dot(N, H), 0.0f);
    float NdotH2 = NdotH * NdotH;
    float denom = NdotH2 * (a2 - 1.0f) + 1.0f;
    denom = M_PI_F * denom * denom;
    return a2 / max(denom, 0.0001f);
}

// Schlick-GGX Geometry (single direction)
inline float geometry_schlick_ggx(float NdotX, float roughness) {
    float r = roughness + 1.0f;
    float k = (r * r) / 8.0f;
    return NdotX / (NdotX * (1.0f - k) + k);
}

// Smith's method (both directions)
inline float geometry_smith(float3 N, float3 V, float3 L, float roughness) {
    float NdotV = max(dot(N, V), 0.0f);
    float NdotL = max(dot(N, L), 0.0f);
    return geometry_schlick_ggx(NdotV, roughness) * geometry_schlick_ggx(NdotL, roughness);
}

// Schlick Fresnel
inline float3 fresnel_schlick(float cos_theta, float3 F0) {
    float t = 1.0f - cos_theta;
    float t2 = t * t;
    float t5 = t2 * t2 * t;
    return F0 + (float3(1.0f) - F0) * t5;
}

// Reinhard tone mapping + gamma correction
inline float3 tonemap_gamma(float3 color) {
    float3 mapped = color / (float3(1.0f) + color);
    float inv_gamma = 1.0f / 2.2f;
    return pow(mapped, float3(inv_gamma));
}

// Random hemisphere direction around normal N
inline float3 random_hemisphere(float3 N, thread uint& seed) {
    float u1 = rand_float(seed);
    float u2 = rand_float(seed);
    float z = u1;
    float r = sqrt(1.0f - z * z);
    float phi = 2.0f * M_PI_F * u2;
    float3 random_dir = float3(r * cos(phi), r * sin(phi), z);

    // Build tangent frame
    float3 up = (abs(N.y) < 0.999f) ? float3(0, 1, 0) : float3(1, 0, 0);
    float3 tangent = normalize(cross(up, N));
    float3 bitangent = cross(N, tangent);

    return normalize(tangent * random_dir.x + bitangent * random_dir.y + N * random_dir.z);
}

// ---------------------------------------------------------------------------
// Möller–Trumbore ray-triangle intersection
// ---------------------------------------------------------------------------
inline bool ray_triangle_intersect(float3 orig,
                                   float3 dir,
                                   float3 v0,
                                   float3 v1,
                                   float3 v2,
                                   thread float& t)
{
    const float epsilon = 1e-6f;

    float3 e1 = v1 - v0;
    float3 e2 = v2 - v0;

    float3 pvec = cross(dir, e2);
    float  det  = dot(e1, pvec);

    if (abs(det) < epsilon) return false;

    float  invDet = 1.0f / det;
    float3 tvec   = orig - v0;

    float u = dot(tvec, pvec) * invDet;
    if (u < 0.0f || u > 1.0f) return false;

    float3 qvec = cross(tvec, e1);
    float  v    = dot(dir, qvec) * invDet;
    if (v < 0.0f || u + v > 1.0f) return false;

    t = dot(e2, qvec) * invDet;
    return t > 0.0f;
}

// ---------------------------------------------------------------------------
// AO occlusion test: any hit within max_dist?
// ---------------------------------------------------------------------------
inline bool ao_occluded_gpu(float3 orig,
                            float3 dir,
                            float  max_dist,
                            constant GPUTriangle* triangles,
                            int triangle_count)
{
    for (int i = 0; i < triangle_count; ++i) {
        float t = 0.0f;
        if (ray_triangle_intersect(orig, dir,
                                   triangles[i].v0.xyz,
                                   triangles[i].v1.xyz,
                                   triangles[i].v2.xyz,
                                   t))
        {
            if (t > 0.01f && t < max_dist) return true;
        }
    }
    return false;
}

// Compute ambient occlusion factor
inline float compute_ao_gpu(float3 position, float3 normal,
                            constant GPUTriangle* triangles,
                            int triangle_count,
                            thread uint& seed)
{
    const int AO_SAMPLES = 4;
    const float AO_RADIUS = 0.3f;
    int unoccluded = 0;
    for (int i = 0; i < AO_SAMPLES; ++i) {
        float3 sample_dir = random_hemisphere(normal, seed);
        if (!ao_occluded_gpu(position, sample_dir, AO_RADIUS, triangles, triangle_count))
            unoccluded++;
    }
    return float(unoccluded) / float(AO_SAMPLES);
}

// ---------------------------------------------------------------------------
// mirror_intersect_gpu
// ---------------------------------------------------------------------------
inline GPUIntersection mirror_intersect_gpu(float3 orig,
                                            float3 dir,
                                            constant GPUTriangle* triangles,
                                            int triangle_count)
{
    GPUIntersection result;
    result.distance       = 1e30f;
    result.triangle_index = -1;
    result.colour         = float3(0.0f);
    result.is_mirror      = false;
    result.position       = float3(0.0f);

    for (int i = 0; i < triangle_count; ++i) {
        float t = 0.0f;
        if (ray_triangle_intersect(orig, dir,
                                   triangles[i].v0.xyz,
                                   triangles[i].v1.xyz,
                                   triangles[i].v2.xyz,
                                   t))
        {
            if (t > 0.001f && t < result.distance) {
                result.distance       = t;
                result.triangle_index = i;
                result.position       = orig + dir * t;
                result.colour         = triangles[i].color.xyz;
            }
        }
    }

    return result;
}

// ---------------------------------------------------------------------------
// shadow_intersect_gpu
// ---------------------------------------------------------------------------
inline bool shadow_intersect_gpu(float3 orig,
                                 float3 dir,
                                 int    id,
                                 constant GPUTriangle* triangles,
                                 int triangle_count)
{
    int lo = max(0,              id - 2);
    int hi = min(triangle_count, id + 3);

    for (int i = lo; i < hi; ++i) {
        float t = 0.0f;
        if (ray_triangle_intersect(orig, dir,
                                   triangles[i].v0.xyz,
                                   triangles[i].v1.xyz,
                                   triangles[i].v2.xyz,
                                   t))
        {
            if (t > 0.0f) return true;
        }
    }
    return false;
}

// ---------------------------------------------------------------------------
// closest_intersect_gpu — with physically correct reflection
// ---------------------------------------------------------------------------
inline GPUIntersection closest_intersect_gpu(float3 orig,
                                             float3 dir,
                                             constant GPUTriangle* triangles,
                                             int triangle_count,
                                             int light,
                                             constant RenderUniforms& uni)
{
    GPUIntersection result;
    result.distance       = 1e30f;
    result.triangle_index = -1;
    result.colour         = float3(0.0f);
    result.is_mirror      = false;
    result.position       = float3(0.0f);

    for (int i = 0; i < triangle_count; ++i) {
        float t = 0.0f;
        if (ray_triangle_intersect(orig, dir,
                                   triangles[i].v0.xyz,
                                   triangles[i].v1.xyz,
                                   triangles[i].v2.xyz,
                                   t))
        {
            if (t > 0.03f && t < result.distance) {
                result.distance       = t;
                result.triangle_index = i;
                result.position       = orig + dir * t;
            }
        }
    }

    // --- Post-process hit ---
    if (result.triangle_index >= 0) {
        int idx = result.triangle_index;

        if (idx == 4 || idx == 5) {
            // Physically correct reflection: R = D - 2(D·N)N
            float3 N = triangles[idx].normal.xyz;
            float3 D_norm = normalize(dir);
            float3 reflect_dir = D_norm - 2.0f * dot(D_norm, N) * N;
            GPUIntersection mirror_hit = mirror_intersect_gpu(result.position,
                                                              reflect_dir,
                                                              triangles,
                                                              triangle_count);
            result.colour    = mirror_hit.colour;
            result.is_mirror = true;
        } else {
            result.colour    = triangles[idx].color.xyz;
            result.is_mirror = false;
        }
    }

    return result;
}

// ---------------------------------------------------------------------------
// direct_light_gpu — PBR Cook-Torrance BRDF
// ---------------------------------------------------------------------------
inline float3 direct_light_gpu(GPUIntersection        point,
                                float3                 view_dir,
                                constant GPUTriangle*  triangles,
                                int                    triangle_count,
                                constant RenderUniforms& uni,
                                thread uint&           seed)
{
    int    idx           = point.triangle_index;
    float3 N             = triangles[idx].normal.xyz;
    float3 albedo        = triangles[idx].color.xyz;
    float  roughness     = triangles[idx].material.x;
    float  metalness     = triangles[idx].material.y;

    float3 surface_light = uni.light_pos.xyz - point.position;
    float  r             = length(surface_light);
    float3 L             = normalize(surface_light);
    float3 V             = normalize(view_dir);
    float3 H             = normalize(V + L);

    float NdotL = max(dot(N, L), 0.0f);

    // PBR: Cook-Torrance
    float3 F0 = mix(float3(0.04f), albedo, metalness);
    float D = distribution_ggx(N, H, roughness);
    float G = geometry_smith(N, V, L, roughness);
    float3 F = fresnel_schlick(max(dot(H, V), 0.0f), F0);

    float3 numerator = D * G * F;
    float denominator = 4.0f * max(dot(N, V), 0.0f) * NdotL + 0.0001f;
    float3 specular = numerator / denominator;

    float3 kS = F;
    float3 kD = (float3(1.0f) - kS) * (1.0f - metalness);

    float attenuation = 1.0f / (4.0f * M_PI_F * r * r);
    float3 radiance = uni.light_colour.xyz * attenuation;

    float3 light_area = (kD * albedo / M_PI_F + specular) * radiance * NdotL;

    // --- Shadow branch ---
    bool do_shadow_check = true;
    if (uni.light_pos.y < -0.20f) {
        do_shadow_check = (point.position.y >= -0.20f);
    }

    if (do_shadow_check) {
        GPUIntersection occluder = closest_intersect_gpu(point.position,
                                                         surface_light,
                                                         triangles,
                                                         triangle_count,
                                                         1,
                                                         uni);

        bool blocked = (occluder.triangle_index >= 0) &&
                       (occluder.distance < 1.0f)     &&
                       (NdotL > 0.0f)                  &&
                       (occluder.triangle_index != idx);

        if (blocked) {
            light_area = float3(0.0f);

            int occluder_idx = occluder.triangle_index;
            float3 soft = float3(0.0f);
            for (int s = 0; s < 10; ++s) {
                float jx = rand_float(seed) * 2.0f - 1.0f;
                float jy = rand_float(seed) * 2.0f - 1.0f;
                float jz = rand_float(seed) * 2.0f - 1.0f;

                float3 jitter_dir = surface_light + float3(0.03f * jx,
                                                           0.03f * jy,
                                                           0.03f * jz);
                if (shadow_intersect_gpu(point.position, jitter_dir,
                                         occluder_idx, triangles, triangle_count)) {
                    // fully in shadow
                } else {
                    soft += albedo;
                }
            }
            light_area += soft / 10.0f;
        }
    }

    return light_area;
}

// ---------------------------------------------------------------------------
// Kernel
// ---------------------------------------------------------------------------
kernel void raytracer_kernel(
    uint3                          gid            [[thread_position_in_grid]],
    constant GPUTriangle*          triangles      [[buffer(0)]],
    constant RenderUniforms&       uni            [[buffer(1)]],
    device   float4*               output_buffer  [[buffer(2)]])
{
    uint x          = gid.x;
    uint y          = gid.y;
    uint sample_idx = gid.z;

    int sw = uni.screen_width;
    int sh = uni.screen_height;

    if (x >= (uint)sw || y >= (uint)sh || sample_idx >= 9u) return;

    // --- Seed ---
    uint seed = (x * 1000u + y) * 9u + sample_idx + 1u;

    // --- Rotation matrix (yaw around Y axis) ---
    float yaw     = uni.yaw;
    float cos_yaw = cos(yaw);
    float sin_yaw = sin(yaw);

    // --- Primary ray focal point ---
    float sw_f = float(sw);
    float sh_f = float(sh);

    float focal_x = (-0.5f + 0.5f / sw_f + float(x) / sw_f)
                    * (uni.focal - uni.camera_pos.z) / uni.f;
    float focal_y = (-0.5f + 0.5f / sh_f + float(y) / sh_f)
                    * (uni.focal - uni.camera_pos.z) / uni.f;

    // --- Anti-aliasing sub-sample grid (3×3, stratified jitter) ---
    int a_idx = int(sample_idx) / 3;
    int b_idx = int(sample_idx) % 3;

    float x_ = -8.0f + (float(b_idx) + rand_float(seed)) * (16.0f / 3.0f);
    float y_ = -8.0f + (float(a_idx) + rand_float(seed)) * (16.0f / 3.0f);

    // --- Sub-pixel position ---
    float3 sub_pixel = float3(
        -0.5f + 0.5f / sw_f + (float(x) + x_) / sw_f,
        -0.5f + 0.5f / sh_f + (float(y) + y_) / sh_f,
        -2.0f
    );

    // --- Ray direction (before rotation) ---
    float3 d_local = float3(focal_x - sub_pixel.x,
                            focal_y - sub_pixel.y,
                            uni.focal - sub_pixel.z);

    // Apply Y-axis rotation: R*d
    float3 d = float3(
         cos_yaw * d_local.x + sin_yaw * d_local.z,
         d_local.y,
        -sin_yaw * d_local.x + cos_yaw * d_local.z
    );

    // View direction (from hit point back toward camera)
    float3 view_dir = -normalize(d);

    // --- Trace primary ray ---
    GPUIntersection intersection = closest_intersect_gpu(
        sub_pixel, d,
        triangles, uni.triangle_count,
        0, uni);

    float3 pixel_colour = float3(0.0f);

    if (intersection.triangle_index >= 0) {
        float3 light_area = direct_light_gpu(intersection,
                                             view_dir,
                                             triangles,
                                             uni.triangle_count,
                                             uni,
                                             seed);

        // Compute ambient occlusion
        int hit_idx = intersection.triangle_index;
        float3 N_hit = triangles[hit_idx].normal.xyz;
        float ao = compute_ao_gpu(intersection.position, N_hit,
                                  triangles, uni.triangle_count, seed);
        float3 ambient = ao * 0.3f * intersection.colour;

        if (intersection.is_mirror) {
            // Re-trace reflected ray for lighting
            float3 N_mirror = triangles[hit_idx].normal.xyz;
            float3 D_norm = normalize(d);
            float3 reflect_dir = D_norm - 2.0f * dot(D_norm, N_mirror) * N_mirror;
            GPUIntersection mirror_isec = mirror_intersect_gpu(
                intersection.position, reflect_dir,
                triangles, uni.triangle_count);

            float3 mirror_shadow = float3(0.0f);
            if (mirror_isec.triangle_index >= 0) {
                mirror_shadow = direct_light_gpu(mirror_isec,
                                                 view_dir,
                                                 triangles,
                                                 uni.triangle_count,
                                                 uni,
                                                 seed);
                // AO for reflected point
                float3 N_mir = triangles[mirror_isec.triangle_index].normal.xyz;
                float ao_mir = compute_ao_gpu(mirror_isec.position, N_mir,
                                             triangles, uni.triangle_count, seed);
                float3 ambient_mir = ao_mir * 0.3f * mirror_isec.colour;
                mirror_shadow += ambient_mir;
            }

            pixel_colour = ambient + 0.5f * (light_area + mirror_shadow);
        } else {
            pixel_colour = ambient + light_area;
        }
    }

    // Apply tone mapping and gamma correction
    pixel_colour = tonemap_gamma(pixel_colour);

    // --- Write output ---
    uint out_idx = (y * uint(sw) + x) * 9u + sample_idx;
    output_buffer[out_idx] = float4(pixel_colour, 1.0f);
}

