    SDL_FillRect(screen, 0, 0);
    if (SDL_MUSTLOCK(screen))
        SDL_LockSurface(screen);

#ifdef USE_METAL
    RenderParams params;
    params.camera_pos   = camera_pos;
    params.light_pos    = light_pos;
