using namespace std;
using glm::vec3;
using glm::mat3;

#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

/* ----------------------------------------------------------------------------*/
/* GLOBAL VARIABLES                                                            */
const int SCREEN_WIDTH = 600;
const int SCREEN_HEIGHT = 600;
SDL_Surface* screen;
int t;
float f = 1.0;
float focal = -0.5;
