// Check if a ray is occluded within max_dist (for AO)
bool ao_occluded(const vec3& start, const vec3& dir, float max_dist)
{
    for (size_t i = 0; i < triangles.size(); i++)
    {
        float t_hit, u_hit, v_hit;
        if (RayTriangleIntersection(start, dir, triangles[i].v0, triangles[i].v1, triangles[i].v2, t_hit, u_hit, v_hit)
            && t_hit > 0.01f && t_hit < max_dist)
        {
            return true;
        }
    }
    return false;
}

// Compute ambient occlusion factor (0 = fully occluded, 1 = fully open)
float compute_ao(const vec3& position, const vec3& normal, unsigned int& seed)
{
    const int AO_SAMPLES = 4;
    const float AO_RADIUS = 0.3f;
    int unoccluded = 0;
    for (int i = 0; i < AO_SAMPLES; i++)
    {
        vec3 sample_dir = random_hemisphere(normal, seed);
        if (!ao_occluded(position, sample_dir, AO_RADIUS))
            unoccluded++;
    }
    return (float)unoccluded / (float)AO_SAMPLES;
}

bool shadow_intersection(const vec3& start, const vec3& dir, int triangle_id, Intersection& cloestIntersection)
{
    bool flag = false;
    float t_hit, u_hit, v_hit;

    int i_start = std::max(0, triangle_id - 2);
    int i_end = std::min((int)triangles.size(), triangle_id + 3);

    for (int i = i_start; i < i_end; i++)
    {
        vec3 v0 = triangles[i].v0;
        vec3 v1 = triangles[i].v1;
        vec3 v2 = triangles[i].v2;

        if (RayTriangleIntersection(start, dir, v0, v1, v2, t_hit, u_hit, v_hit) && t_hit > 0.0f)
        {
            flag = true;
            break;
        }
    }

    if (flag)
        return true;
    else
        return false;
}

bool mirror_intersection(const vec3& start, const vec3& dir, const vector<Triangle>& triangles, Intersection& cloestIntersection)
{
    bool flag = false;
    float min = 0.0;
    int triangle_index;
    vec3 v0, v1, v2;

    for (size_t i = 0; i < triangles.size(); i++)
    {
        v0 = triangles[i].v0;
        v1 = triangles[i].v1;
        v2 = triangles[i].v2;

        float t_hit, u_hit, v_hit;
        if (RayTriangleIntersection(start, dir, v0, v1, v2, t_hit, u_hit, v_hit) && t_hit > 0.001f)
        {
            if (!flag)
            {
                min = t_hit;
                triangle_index = i;
            }
            flag = true;
            if (min > t_hit)
            {
                min = t_hit;
                triangle_index = i;
            }
        }
    }

    if (flag)
    {
        cloestIntersection.position = start + min * dir;
        cloestIntersection.distance = min;
        cloestIntersection.triangle_index = triangle_index;
        cloestIntersection.colour = triangles[triangle_index].color;
        return true;
    }
    else
        return false;
}

