                       (occluder.distance < 1.0f)     &&
                       (occluder.triangle_index != idx);

        if (blocked) {
            int occluder_idx = occluder.triangle_index;
            int visible_count = 0;
            for (int s = 0; s < 10; ++s) {
                float jx = rand_float(seed) * 2.0f - 1.0f;
                float jy = rand_float(seed) * 2.0f - 1.0f;
                float jz = rand_float(seed) * 2.0f - 1.0f;

